// Calculate yesterday's date for sync
const now = new Date();
const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);
const syncDate = yesterday.toISOString().split('T')[0];

return [{ json: {
  syncDate,
  nowIso: now.toISOString()
} }];

// Google Ads API not configured — graceful skip
return [{ json: {
  status: 'skipped',
  reason: 'Google Ads API not configured — set TG_GOOGLE_ADS_CUSTOMER_ID variable to enable',
  timestamp: new Date().toISOString()
} }];

// Build GAQL query for ad_group level metrics
const syncDate = $('Calculate Sync Date').first().json.syncDate;

const query = `SELECT campaign.id, campaign.name, ad_group.id, ad_group.name, metrics.impressions, metrics.clicks, metrics.conversions, metrics.cost_micros, metrics.conversions_value, metrics.ctr, metrics.average_cpc, metrics.search_impression_share FROM ad_group WHERE segments.date = '${syncDate}'`;

return [{ json: {
  query,
  syncDate,
  customerId: $vars.TG_GOOGLE_ADS_CUSTOMER_ID
} }];

// Transform Google Ads API response to google_ads_daily schema
const response = $input.first().json;
const syncDate = $('Calculate Sync Date').first().json.syncDate;

// Check for API error (continueOnFail)
if (response.error || response.statusCode >= 400) {
  return [{ json: {
    status: 'error',
    reason: 'Google Ads API call failed',
    error: response.error || response.body || 'Unknown error',
    syncDate
  } }];
}

// Parse searchStream response — returns array of result batches
const body = response.body || response;
const results = Array.isArray(body) ? body : (body.results || []);

if (!results.length) {
  return [{ json: { status: 'no_data', syncDate, rows: 0 } }];
}

// Flatten all result batches
const rows = [];
for (const batch of results) {
  const batchResults = batch.results || [batch];
  for (const row of batchResults) {
    const campaign = row.campaign || {};
    const adGroup = row.adGroup || {};
    const metrics = row.metrics || {};

    const costMicros = parseInt(metrics.costMicros || '0', 10);
    const cost = costMicros / 1000000;
    const clicks = parseInt(metrics.clicks || '0', 10);
    const impressions = parseInt(metrics.impressions || '0', 10);
    const conversions = parseFloat(metrics.conversions || '0');
    const conversionValue = parseFloat(metrics.conversionsValue || '0');

    rows.push({
      report_date: syncDate,
      campaign_id: campaign.id || null,
      campaign_name: campaign.name || null,
      ad_group_id: adGroup.id || null,
      ad_group_name: adGroup.name || null,
      impressions,
      clicks,
      cost: Math.round(cost * 100) / 100,
      conversions,
      conversion_value: Math.round(conversionValue * 100) / 100,
      ctr: parseFloat(metrics.ctr || '0'),
      avg_cpc: clicks > 0 ? Math.round((cost / clicks) * 100) / 100 : 0,
      roas: cost > 0 ? Math.round((conversionValue / cost) * 100) / 100 : 0,
      search_impression_share: parseFloat(metrics.searchImpressionShare || '0')
    });
  }
}

return rows.map(r => ({ json: r }));

// Log skip/error from Transform step
const data = $input.first().json;
return [{ json: {
  status: data.status || 'skipped',
  reason: data.reason || data.error || 'No valid ad data to upsert',
  syncDate: data.syncDate || $('Calculate Sync Date').first().json.syncDate,
  timestamp: new Date().toISOString()
} }];
